INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05880', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '對於研究對象的保護和倫理議題，下列敘述何者正確？ 對於告知或參與同意書之取得，有時很麻煩，所以可以省略 為了保護研究對象，有些嚴謹的單位之研究案申請，需要再遞送至人體試驗暨研究倫理委員會 （Institutional Review Board, IRB）審查 在一項告知受訪者為匿名調查的研究中，為了方便追蹤，可在每位受訪者的問卷進行編碼 依據特定研究目的所蒐集或申請之資料，在研究結束後，可在未經申請同意之下，移作其他用途', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05881', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於變異數分析（又稱變異量分析，ANOVA）的說明，下列何者錯誤？ 可用來檢定因子（自變項或獨立變項）對依變項是否有關係或影響的統計方法 可用來檢定3個或3個以上母體平均數是否相等的統計方法 當計算之F值小於臨界值時，可以拒絕虛無假設 拒絕虛無假設之後，可藉由多重比較發現各個母體之間的差異', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05882', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關變項的敘述，何者錯誤？ 變項由概念演化而來 變項是概念的具體延伸 變項是屬性的集合 自變項和依變項之間，一定只有正相關和負相關兩種可能', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05883', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '一種關心評估方案的最終成效，以及是否應該繼續進行方案，這是指下列何種方案評估？ 形成性評估（formative evaluations）  診斷性評估（diagnostic evaluations） 總結性評估（summative evaluations）  過程評估（process evaluations）', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05884', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者擬了解機構式及社區式安養老人與其生活適應的關係，設計一份生活適應量表進行測量，以量表 總加得分作為生活適應程度高低情形。研究者應使用下列何種統計方法檢定二者之關係？ 卡方檢定  獨立樣本t檢定    皮爾遜積差相關分析  因素分析', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05885', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '由於沒有測量方式可以避開偏誤，因此研究者會使用多種不同方法蒐集相同資料，確認是否得到類似的 研究發現，是指下列何種方法？ 三角檢測法  反覆法  回溯檢視法  正反驗證法', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05886', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '即使是研究者也無法根據所提供的特定資訊辨識出是那一個體，此為下列何種研究倫理議題？ 通則化  保密性  匿名性  自願性', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05887', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列那一變項的測量，其屬性是屬於連續性變項（continuous variable）？ 薪資  職業  教育程度  名次', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05888', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某人的研究問題為：「為什麼某些地區容易產生較高的自殺比率」，你認為這個研究的分析單位是： 幫派團體  企業組織  交換電子郵件  地區別', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05889', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '個案研究法是一種質性研究的方法，下列敘述何者錯誤？ 描述是其主要目標，但也接受嘗試性的解釋 描述一個草根社區組織的誕生與經驗是其相關案例 研究者的功能是充當被研究者的資源 個案研究法的獨特性是在於其研究關注只有一個特定的個案', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
